import{_ as o,o as t,c as a,ag as n}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Tor Access","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tor-access.md","filePath":"guide/tor-access.md","lastUpdated":1775031224000}'),r={name:"guide/tor-access.md"};function s(i,e,c,d,l,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="tor-access" tabindex="-1">Tor Access <a class="header-anchor" href="#tor-access" aria-label="Permalink to &quot;Tor Access&quot;">​</a></h1><p>getbased is fully accessible as a Tor hidden service. When you visit the clearnet site or app using <a href="https://www.torproject.org/download/" target="_blank" rel="noreferrer">Tor Browser</a>, a purple &quot;.onion available&quot; badge appears in the address bar — click it to switch to the .onion version.</p><h2 id="onion-addresses" tabindex="-1">.onion Addresses <a class="header-anchor" href="#onion-addresses" aria-label="Permalink to &quot;.onion Addresses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Address</th></tr></thead><tbody><tr><td><strong>Website</strong></td><td><code>p75tbgf5smjkrq7pqap5bkq6esrgin66q6td2lmukbxo5r3gyocfqxid.onion</code></td></tr><tr><td><strong>App</strong></td><td><code>iobqafpywmncin7m2wpvbemouvulaeb7jnvtvugxnru4gpneushb5jyd.onion</code></td></tr><tr><td><strong>Sync relay</strong></td><td><code>udou6gehyfpfccdjpibmuttaoauawmh5cgzszffnskbvczppvr2sfjad.onion</code></td></tr></tbody></table><h2 id="what-changes-on-onion" tabindex="-1">What Changes on .onion <a class="header-anchor" href="#what-changes-on-onion" aria-label="Permalink to &quot;What Changes on .onion&quot;">​</a></h2><ul><li><strong>AI API calls</strong> go directly to your provider (Anthropic, OpenRouter, Venice) over HTTPS — the Vercel proxy is bypassed</li><li><strong>Sync relay</strong> automatically switches to the .onion relay address (<code>ws://</code>) instead of the clearnet relay (<code>wss://</code>)</li><li><strong>All app features work</strong> — PDF import, AI chat, encryption, DNA import, everything</li></ul><h2 id="sync-across-clearnet-and-onion" tabindex="-1">Sync Across Clearnet and .onion <a class="header-anchor" href="#sync-across-clearnet-and-onion" aria-label="Permalink to &quot;Sync Across Clearnet and .onion&quot;">​</a></h2><p>Your sync mnemonic works on both clearnet and .onion. The app detects which environment you&#39;re in and uses the correct relay:</p><ul><li>Clearnet: <code>wss://sync.getbased.health</code></li><li>Tor: <code>ws://udou6gehyfpfccdjpibmuttaoauawmh5cgzszffnskbvczppvr2sfjad.onion</code></li></ul><p>Both relay endpoints point to the same server. Data synced from clearnet is available on .onion and vice versa.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li><strong>OpenRouter OAuth</strong> requires a clearnet callback URL — use API key entry instead when on .onion</li><li><strong>Umami analytics</strong> (privacy-respecting, no cookies) is not loaded on .onion</li><li><strong>AI providers are clearnet services</strong> — your prompts travel over HTTPS to the provider. For maximum privacy, use Venice with <a href="./encryption.html#venice-end-to-end-encryption-e2ee">E2EE</a> enabled</li></ul>',12)])])}const g=o(r,[["render",s]]);export{u as __pageData,g as default};
